const timeZone = 'America/New_York';
const today = new Date().toLocaleDateString('en-US', { 
  weekday: 'long', 
  timeZone 
});

const rows = $input.all();

const todayRows = rows.filter(item => {
  const r = item.json;
  const dayMatch = r['Day-week']?.trim().toLowerCase() === today.toLowerCase();
  const status = (r.Status || '').trim().toLowerCase();
  const isPending = status === 'pending' || status === '';
  return dayMatch && isPending;
});

if (todayRows.length === 0) {
  return []; 
}

return todayRows;

const item = $input.first().json;
const designInfo = $('Get Canva Design Info').item.json.design;
const pagesInfo = $('Get Canva Pages Info').item.json.items || [];

// 1. CONTEO REAL DE PÁGINAS
const pageCount = pagesInfo.length || designInfo.page_count || 1;

// 2. DIMENSIONES REALES
const firstPage = pagesInfo[0] || {};
const width = firstPage.dimensions?.width || designInfo.thumbnail?.width || 1080;
const height = firstPage.dimensions?.height || designInfo.thumbnail?.height || 1080;
const ratio = width / height;

// 3. DETECCIÓN TÉCNICA (ORIGINAL)
const isAnimated = designInfo.is_animated === true;
const supportsVideo = designInfo.urls?.view_url?.includes('.mp4') ?? false;
const hasDuration = pagesInfo.some(p => p.duration > 0) || (designInfo.duration > 0);
const isVideoTechnical = isAnimated || supportsVideo || hasDuration;

// 4. DETECCIÓN POR TÍTULO (SOLO PARA CAROUSELS)
const title = (designInfo.title || "").toLowerCase();
const titleHasVideo = title.includes("video") || title.includes("mp4") || title.includes("reel");

let format = 'post';
let mediatype = 'image';
let canvaExportFormat = 'png';
let canvaQuality = 'horizontal_1080p';

// --- LÓGICA DE CLASIFICACIÓN ---

if (ratio < 0.75) { 
  // 🟢 STORY: Mantiene lógica original (Automática)
  format = 'stories';
  canvaQuality = 'vertical_1080p';
  if (isVideoTechnical || pageCount > 1) {
    mediatype = 'video';
    canvaExportFormat = 'mp4';
  }
} else if (pageCount > 1) {
  // 🔵 CAROUSEL: Lógica Especial (Técnica + Título)
  format = 'carousel';
  // Si el usuario puso "video" en el título O si Canva lo detecta técnicamente
  if (titleHasVideo || isVideoTechnical) {
    mediatype = 'video';
    canvaExportFormat = 'mp4';
  } else {
    mediatype = 'image';
    canvaExportFormat = 'png';
  }
} else {
  // 🟡 POST: Mantiene lógica original (Automática)
  format = 'post';
  if (isVideoTechnical) {
    mediatype = 'video';
    canvaExportFormat = 'mp4';
  }
}

return {
  json: {
    format,
    mediatype,
    getlate_media_type: mediatype,
    canvaExportFormat,
    canvaQuality,
    pages: pageCount,
    title: designInfo.title,
    debug: { isVideoTechnical, titleHasVideo, ratio, pageCount }
  }
};

