const nextToPublish = rows.find(item => {
  const status = (item.json.Status || '').trim().toLowerCase();
  return status !== 'published';
});

if (!nextToPublish) {
  // Si no hay nada pendiente, el workflow se detiene aquí
  return []; 
}

// Retornamos solo esa fila para procesarla
return [nextToPublish];

// Obtenemos el número total de páginas desde el nodo Detect Format
const totalPages = $('Detect Format').item.json.pages || 1;
const designId = $('Pick By Raw').item.json.Design_ID;
const results = [];

// Creamos un elemento por cada página para generar el bucle
for (let i = 1; i <= totalPages; i++) {
  results.push({
    json: {
      page_number: i,
      total_pages: totalPages,
      Design_ID: designId
    }
  });
}

return results;

