  image_url_5: cleanUrl(item.image_url_5),
  image_url_6: cleanUrl(item.image_url_6),
  image_url_7: cleanUrl(item.image_url_7)
};

// Generamos el array para el mediaItemsString (por si lo sigues usando)
const validMedia = Object.values(urls)
  .filter(url => url && url.length > 10)
  .map(url => ({ url, type: detectedMediaType }));

return [{
  json: {
    Design_ID:   item.Design_ID || '',
